import { Component, signal, inject } from '@angular/core';
import { RouterLink, RouterLinkActive } from '@angular/router';
import { CommonModule } from '@angular/common';
import { AuthService } from '../../../core/services/auth.service';
import { ClickOutsideDirective } from '../../directives/click-outside.directive';

@Component({
  selector: 'app-navbar',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive, ClickOutsideDirective],
  templateUrl: './navbar.component.html',
  styleUrl: './navbar.component.scss'
})
export class NavbarComponent {
  authService = inject(AuthService);
  mobileMenuOpen = signal(false);
  userMenuOpen = signal(false);

  currentUser$ = this.authService.currentUser$;

  toggleMobileMenu() {
    this.mobileMenuOpen.update(value => !value);
  }

  closeMobileMenu() {
    this.mobileMenuOpen.set(false);
  }

  toggleUserMenu() {
    this.userMenuOpen.update(value => !value);
  }

  closeUserMenu() {
    this.userMenuOpen.set(false);
  }

  getInitials(name: string): string {
    return name
      .split(' ')
      .map(n => n[0])
      .join('')
      .toUpperCase()
      .substring(0, 2);
  }

  logout() {
    this.closeUserMenu();
    this.authService.logout();
  }
}
<nav class="navbar">
  <div class="navbar-container">
    <div class="navbar-brand">
      <a routerLink="/" class="brand-logo">
        <svg class="sparkle-icon" width="20" height="20" viewBox="0 0 24 24" fill="none">
          <path d="M12 2L14.5 9.5L22 12L14.5 14.5L12 22L9.5 14.5L2 12L9.5 9.5L12 2Z" fill="url(#gradient)" stroke="url(#gradient)" stroke-width="1.5"/>
          <defs>
            <linearGradient id="gradient" x1="2" y1="2" x2="22" y2="22">
              <stop offset="0%" stop-color="#6366f1"/>
              <stop offset="100%" stop-color="#8b5cf6"/>
            </linearGradient>
          </defs>
        </svg>
        <span class="logo-text">ResumeAI</span>
      </a>
    </div>

    <button class="mobile-menu-toggle" (click)="toggleMobileMenu()" [attr.aria-expanded]="mobileMenuOpen()">
      <svg *ngIf="!mobileMenuOpen()" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
        <line x1="3" y1="12" x2="21" y2="12"></line>
        <line x1="3" y1="6" x2="21" y2="6"></line>
        <line x1="3" y1="18" x2="21" y2="18"></line>
      </svg>
      <svg *ngIf="mobileMenuOpen()" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
        <line x1="18" y1="6" x2="6" y2="18"></line>
        <line x1="6" y1="6" x2="18" y2="18"></line>
      </svg>
    </button>

    <!-- Logged In View -->
    <ng-container *ngIf="currentUser$ | async as user; else loggedOut">
      <div class="navbar-links" [class.mobile-open]="mobileMenuOpen()">
        <a routerLink="/analyzer" routerLinkActive="active" (click)="closeMobileMenu()">Analyzer</a>
        <a routerLink="/history" routerLinkActive="active" (click)="closeMobileMenu()">History</a>
      </div>

      <div class="user-menu-wrapper">
        <button class="user-avatar" (click)="toggleUserMenu()" [attr.aria-expanded]="userMenuOpen()">
          <span class="avatar-circle">{{ getInitials(user.name) }}</span>
        </button>

        <div class="user-dropdown" *ngIf="userMenuOpen()" clickOutside (clickOutside)="closeUserMenu()">
          <div class="user-info">
            <div class="user-name">{{ user.name }}</div>
            <div class="user-email">{{ user.email }}</div>
          </div>
          <div class="dropdown-divider"></div>
          <button class="dropdown-item" (click)="logout()">
            <svg width="18" height="18" viewBox="0 0 20 20" fill="currentColor">
              <path fill-rule="evenodd" d="M3 3a1 1 0 00-1 1v12a1 1 0 102 0V4a1 1 0 00-1-1zm10.293 9.293a1 1 0 001.414 1.414l3-3a1 1 0 000-1.414l-3-3a1 1 0 10-1.414 1.414L14.586 9H7a1 1 0 100 2h7.586l-1.293 1.293z" clip-rule="evenodd"/>
            </svg>
            Sign out
          </button>
        </div>
      </div>
    </ng-container>

    <!-- Logged Out View -->
    <ng-template #loggedOut>
      <div class="auth-buttons">
        <a routerLink="/login" class="btn-ghost">Sign in</a>
        <a routerLink="/register" class="btn-primary">Get Started</a>
      </div>
    </ng-template>
  </div>
</nav>
